-- Create "model_rate_limits" table
CREATE TABLE "model_rate_limits" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "model_id" bigint NOT NULL,
  "rpm_limit" bigint NOT NULL DEFAULT 0,
  "enabled" boolean NOT NULL DEFAULT true,
  PRIMARY KEY ("id")
);
-- Create index "modelratelimit_enabled" to table: "model_rate_limits"
CREATE INDEX "modelratelimit_enabled" ON "model_rate_limits" ("enabled");
-- Create index "modelratelimit_model_id" to table: "model_rate_limits"
CREATE UNIQUE INDEX "modelratelimit_model_id" ON "model_rate_limits" ("model_id");
